mapper.select:
SELECT UC.login_id as loginId
FROM USERS U
JOIN USER_CREDENTIAL UC ON U.USER_ID = UC.USER_ID
WHERE U.DELETED_YN = 'N'
  AND U.NAME = #{name}
  AND U.EMAIL = #{email}

SELECT U.USER_ID as userId
FROM USERS U
         JOIN USER_CREDENTIAL UC ON U.USER_ID = UC.USER_ID
WHERE U.DELETED_YN = 'N'
  AND UC.LOGIN_ID = #{loginId}
  AND U.NAME = #{name}
  AND U.EMAIL = #{email}

mapper.update:
UPDATE USER_CREDENTIAL
SET PASSWORD = #{password},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}
